module counter_3bit_updown(
    input clk,
    input rst,
    input mode,
    output reg [2:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
    if (rst)
        count <= 3'b000;
    else if (mode)
        count <= count + 1;
    else
        count <= count - 1;

endmodule
